function solve(nums) {
    const N = nums.length;
    let totalGoodSubarrays = 0;

    // 1. Precompute positions of every value
    const positions = new Map();
    for (let i = 0; i < N; i++) {
        if (!positions.has(nums[i])) {
            positions.set(nums[i], []);
        }
        positions.get(nums[i]).push(i);
    }

    // 2. Iterate over k, assuming nums[k] is the required element X
    for (let k = 0; k < N; k++) {
        const X = nums[k];

        // Find k_prev and k_next (for tie-breaking: k must be the first occurrence of X)
        const indexList = positions.get(X);
        let k_prev = -1;
        let k_next = N;

        // Find index of k in the sorted list
        let idx_k = indexList.indexOf(k);
        if (idx_k !== -1) {
            if (idx_k > 0) {
                k_prev = indexList[idx_k - 1];
            }
            if (idx_k < indexList.length - 1) {
                k_next = indexList[idx_k + 1];
            }
        }

        // Find L and R (maximal range where all elements are submasks of X)
        let L = k;
        while (L > 0 && (nums[L - 1] | X) === X) {
            L--;
        }

        let R = k;
        while (R < N - 1 && (nums[R + 1] | X) === X) {
            R++;
        }

        // Determine iteration bounds for i and j based on k, k_prev, k_next, L, R
        // i must be <= k AND i > k_prev AND i >= L
        const i_min = Math.max(0, L);
        const i_max = Math.min(k, k_prev + 1);

        // j must be >= k AND j < k_next AND j <= R
        const j_upper_bound = Math.min(N - 1, R, k_next - 1);

        // 3. Iterate i backwards from k down to i_min
        let current_or = 0;
        for (let i = k; i >= i_min; i--) {
            // Calculate O[i..k] incrementally
            current_or = current_or | nums[i];

            // Check condition 3: OR(nums[i..k]) must equal X
            if (current_or === X) {
