import java.util.*;

public class Solution {
    public static long solve(long[] nums) {
        int N = nums.length;
        long totalGoodSubarrays = 0;

        // 1. Precompute positions of every value
        // Map: value -> List of indices
        Map<Long, List<Integer>> positions = new HashMap<>();
        for (int i = 0; i < N; i++) {
            long val = nums[i];
            positions.computeIfAbsent(val, k -> new ArrayList<>()).add(i);
        }

        // 2. Iterate over k, assuming nums[k] is the required element X
        for (int k = 0; k < N; k++) {
            long X = nums[k];

            // Find k_prev and k_next
            List<Integer> indexList = positions.get(X);

            int k_prev = -1;
            int k_next = N;

            // Find index of k in the sorted list of indices for X
            int idx_k = -1;
            for(int i = 0; i < indexList.size(); i++) {
                if (indexList.get(i) == k) {
                    idx_k = i;
                    break;
                }
            }

            if (idx_k != -1) {
                if (idx_k > 0) {
                    k_prev = indexList.get(idx_k - 1);
                }
                if (idx_k < indexList.size() - 1) {
                    k_next = indexList.get(idx_k + 1);
                }
            }

            // Find L and R (maximal range where all elements are submasks of X)
            // L: left boundary (inclusive)
            int L = k;
            while (L > 0) {
                long prevVal = nums[L - 1];
                // Check if prevVal is a submask of X: (prevVal | X) == X
                if ((prevVal | X) == X) {
                    L--;
                } else {
                    break;
                }
            }

            // R: right boundary (inclusive)
            int R = k;
            while (R < N - 1) {
                long nextVal = nums[R + 1];
                // Check if nextVal is a submask of X: (nextVal | X) == X
                if ((nextVal | X) == X) {
                    R++;
                } else {
                    break;
                }
            }

            // Determine iteration bounds for i and j based on k, k_prev, k_next, L, R

            // i must be <= k AND i > k_prev AND i >= L
            int i_min = Math.max(0, L);
            int i_max = Math.min(k, k_prev + 1);

            // j must be >= k AND j < k_next AND j <= R
            int j_upper_bound = Math.min(N - 1, Math.min(R, k_next - 1));

            // 3. Iterate i backwards from k down to i_min
            long current_or = 0;
            for (int i = k; i >= i_min; i--) {
                // Calculate O[i..k] incrementally
                current_or |= nums[i];

                // Check condition 3: OR(nums[i..k]) must equal X
                if (current_or == X) {
                    // If O[i..k] = X, then O[i..j] = X for all j in [k, j_upper_bound] 
                    // because all nums[l] in [i, j_upper_bound] are submasks of X.

                    // Number of valid j's is (j_upper_bound - k + 1)
                    // Since k <= j_upper_bound, this count is non-negative.
                    long count_j = (long)j_upper_bound - k + 1;
                    totalGoodSubarrays += count_j;
                }
            }
